export const AspectRatioRtl = (): Html => {
  const h = html<never>()
  const { dir, values } = arabicAspectRatioRtl

  return h.figure(
    [h.Class('w-full max-w-sm'), h.Dir(dir)],
    [
      aspectRatio(16 / 9, 'rounded-lg bg-muted'),
      h.figcaption(
        [h.Class('mt-2 text-center text-sm text-muted-foreground')],
        [values.caption],
      ),
    ],
  )
}
